module RefModule (
    input clk,
    input rst,
    input en,
    output [4:0] q
);

    reg [4:0] unused_q_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            unused_q_reg <= 5'b0;
        else if (en)
            unused_q_reg <= unused_q_reg + 3;
    end

    assign q = unused_q_reg;

endmodule
